SELECT 
  ?rider_id
  ?rider_name
  ?rider_type
  ?participant_sk
  ?issue_age
  ?party_full_name
  ?party_gender
  ?underwriting_class
  ?tobacco_premium_basis
WHERE {
  ?rider a <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/Rider> ;
         <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/Rider/rider_id> ?rider_id ;
         <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/Rider/is_deleted> ?_b0 .

  OPTIONAL { ?rider <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/Rider/rider_name> ?rider_name . }
  OPTIONAL { ?rider <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/Rider/rider_type> ?rider_type . }

  ?riderParticipant a <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/RiderParticipant> ;
                    <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/RiderParticipant/is_deleted> ?_b1 ;
                    <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/RiderParticipant/participant_sk> ?participant_sk .

  OPTIONAL { ?riderParticipant <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/RiderParticipant/issue_age> ?issue_age . }

  ?riderParticipant <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/RiderParticipant/hasHolding> ?holding .
  ?rider <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/Rider/hasHolding> ?holding .

  ?lifeParticipant a <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/LifeParticipant> ;
                   <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/LifeParticipant/participant_sk> ?participant_sk ;
                   <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/LifeParticipant/is_deleted> ?_b2 .

  OPTIONAL { ?lifeParticipant <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/LifeParticipant/underwriting_class> ?underwriting_class . }
  OPTIONAL { ?lifeParticipant <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/LifeParticipant/tobacco_premium_basis> ?tobacco_premium_basis . }

  ?lifeParticipant <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/LifeParticipant/hasParty> ?party .
  ?party a <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/Party> ;
         <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/Party/is_deleted> ?_b3 .

  OPTIONAL { ?party <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/Party/full_name> ?party_full_name . }
  OPTIONAL { ?party <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/Party/gender> ?party_gender . }

  FILTER(LCASE(STR(?_b0)) IN ("false", "0", "f", "no", "n"))
  FILTER(LCASE(STR(?_b1)) IN ("false", "0", "f", "no", "n"))
  FILTER(LCASE(STR(?_b2)) IN ("false", "0", "f", "no", "n"))
  FILTER(LCASE(STR(?_b3)) IN ("false", "0", "f", "no", "n"))
}
ORDER BY ?rider_id ?participant_sk

SELECT DISTINCT ?holdingId ?partyFullName
WHERE {
  ?lp a <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/LifeParticipant> ;
      <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/LifeParticipant/holding_id> ?holdingId ;
      <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/LifeParticipant/party_id> ?lpPartyId ;
      <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/LifeParticipant/is_deleted> ?_b0 .

  ?cov a <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/Coverage> ;
       <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/Coverage/holding_id> ?holdingId ;
       <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/Coverage/party_id> ?covPartyId ;
       <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/Coverage/coverage_type> "Base" ;
       <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/Coverage/is_deleted> ?_b1 .

  FILTER (?lpPartyId = ?covPartyId)

  ?party a <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/Party> ;
         <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/Party/party_key> ?lpPartyId ;
         <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/Party/full_name> ?partyFullName ;
         <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/Party/is_deleted> ?_b2 .

  FILTER(LCASE(STR(?_b0)) IN ("false", "0", "f", "no", "n"))
  FILTER(LCASE(STR(?_b1)) IN ("false", "0", "f", "no", "n"))
  FILTER(LCASE(STR(?_b2)) IN ("false", "0", "f", "no", "n"))
}

SELECT ?productName
WHERE {
  ?cp a <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/CoverageProduct> ;
      <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/CoverageProduct/product_name> ?productName .
}
ORDER BY ?productName
LIMIT 10

SELECT (SUBSTR(?transaction_date, 1, 7) AS ?month) (SUM(?transaction_amount) AS ?total_amount)
WHERE {
  ?fa a <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/FinancialActivity> ;
      <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/FinancialActivity/transaction_date> ?transaction_date ;
      <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/FinancialActivity/transaction_amount> ?transaction_amount ;
      <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/FinancialActivity/is_deleted> ?is_deleted .
  FILTER(?is_deleted = false)
  FILTER(SUBSTR(?transaction_date, 1, 4) = "2024")
}
GROUP BY (SUBSTR(?transaction_date, 1, 7))
ORDER BY (SUBSTR(?transaction_date, 1, 7))

SELECT (COUNT(*) AS ?n)
WHERE {
  ?r a <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/Relation> ;
     <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/Relation/is_deleted> ?_b0 .
  FILTER(0 = 1)

  FILTER(LCASE(STR(?_b0)) IN ("false", "0", "f", "no", "n"))
}

SELECT (COUNT(?party) AS ?n)
WHERE {
  ?party a <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/Party> ;
         <http://curated-layer-ontology-20260614-175213/ontology/vkg-ontology_curated_layer-8b3529dc/Party/is_deleted> ?_b0 .

  FILTER(LCASE(STR(?_b0)) IN ("false", "0", "f", "no", "n"))
}
